import sailpoint.object.Attributes;
  import sailpoint.object.Certifiable;
  import sailpoint.object.Certification;
  import sailpoint.object.CertificationAction;
  import sailpoint.object.CertificationEntity;
  import sailpoint.object.CertificationItem;
  import sailpoint.object.EntitlementSnapshot;
  import sailpoint.object.EntitlementGroup;
  import sailpoint.object.Filter;
  import sailpoint.object.ManagedAttribute;
  import sailpoint.tools.Util;

    private String convertGSuiteGroupValue(String value) {

      Filter valueFilter = Filter.eq("value", value);
      Filter appNameFilter = Filter.eq("application.name", "GSuite");
      Filter attributeFilter = Filter.eq("attribute", "Groups");
      Filter andFilter = Filter.and(valueFilter, appNameFilter, attributeFilter);

      if (ops != null && andFilter != null) {

        ManagedAttribute ma = context.getUniqueObject(ManagedAttribute.class, andFilter);

        if (ma != null) {

          if (Util.isNotNullOrEmpty(ma.getFullName())) {

            value = ma.getFullName(); //Get the value IdentityIQ uses for constructing names within certifications

          }

        }

      }

      return value;

    }

  if (certification != null) {

    List entities = certification.getEntities();

    for (CertificationEntity entity : entities) {

      List certItems = entity.getItems();

      for (CertificationItem item : certItems) {

          EntitlementSnapshot entitlementSnapshot = item.getExceptionEntitlements();

          if (entitlementSnapshot != null && Util.isNotNullOrEmpty(entitlementSnapshot.getAttributes().getString("childGroups"))) {

            String convertedValue = convertGSuiteGroupValue(entitlementSnapshot.getAttributes().getString("childGroups"));

            entitlementSnapshot.getAttributes().put("childGroups", convertedValue); //Update the value the UI uses for the Description column of line items within an Access Review

          }

      }

    }

  }
